const raw = $input.first().json;
const body = raw.body ?? raw;
const headers = raw.headers ?? {};

const ref = body.ref || '';
const branch = ref.startsWith('refs/heads/') ? ref.replace('refs/heads/', '') : (body.branch || 'unknown');
const shaFull = body.after || body.head_commit?.id || '';
const sha = String(shaFull).slice(0, 12) || 'latest';
const repo = body.repository?.full_name || body.repository?.name || 'unknown';
const pusher = body.pusher?.name || body.sender?.login || 'unknown';
const isMain = branch === 'main' || branch === 'master';

return [{
  json: {
    ref,
    branch,
    sha,
    repo,
    pusher,
    isMain,
  }
}];

const parse = $('Parse GitHub Payload').first().json;
const item = $input.first().json;
const stdout = String(item.stdout ?? item.data ?? JSON.stringify(item));
const stderr = String(item.stderr ?? '');
const success = stdout.includes('Deployed') || (!stdout.toLowerCase().includes('error') && !stderr.toLowerCase().includes('error'));

return [{
  json: {
    success,
    branch: parse.branch,
    sha: parse.sha,
    repo: parse.repo,
    pusher: parse.pusher,
    image: 'smitambalia/n8n:' + parse.sha,
    stdout: stdout.slice(-4000),
    stderr: stderr.slice(-2000),
    summary: success
      ? ('CI OK: ' + parse.repo + '@' + parse.sha + ' -> k3s')
      : ('CI FAILED: ' + parse.repo + '@' + parse.sha),
  }
}];
